// ========================================
// WF1 v8.1 - SPLIT & FILTER BY SEND LIMIT
// Giới hạn: 2 lần/ngày max
// ========================================

const response = $input.first().json;
const results = response.results || [];

if (results.length === 0) {
  console.log('[WF1 v8.1] Không có Clarification nào cần gửi email');
  return [];
}

console.log(`[WF1 v8.1] Query trả về ${results.length} Clarifications`);

// Get today's date string (YYYY-MM-DD)
const today = new Date().toISOString().split('T')[0];
console.log(`[WF1 v8.1] Today: ${today}`);

// Filter items that can receive email
const eligibleItems = [];
const skippedItems = [];

results.forEach((item, index) => {
  const props = item.properties || {};

  // Get title for logging
  let tieuDe = '';
  for (const [name, data] of Object.entries(props)) {
    if (data.type === 'title' && data.title?.[0]) {
      tieuDe = data.title[0].plain_text || '';
      break;
    }
  }

  // Get send count
  let soLanGui = 0;
  for (const [name, data] of Object.entries(props)) {
    if (data.type === 'number' && name.toLowerCase().includes('số lần')) {
      soLanGui = data.number || 0;
      break;
    }
  }

  // Get last send date
  let ngayGuiGanNhat = '';
  for (const [name, data] of Object.entries(props)) {
    if (data.type === 'date' && name.toLowerCase().includes('ngày gửi')) {
      ngayGuiGanNhat = data.date?.start || '';
      break;
    }
  }

  // Extract just date part if datetime
  if (ngayGuiGanNhat) {
    ngayGuiGanNhat = ngayGuiGanNhat.split('T')[0];
  }

  // Check eligibility
  // Rule: Max 2 emails per day
  const isToday = ngayGuiGanNhat === today;
  const canSend = !isToday || soLanGui < 2;

  console.log(`[WF1 v8.1] #${index + 1} "${tieuDe.substring(0, 30)}..." | Gửi: ${soLanGui} lần | Ngày gần nhất: ${ngayGuiGanNhat} | Today: ${isToday} | Can Send: ${canSend}`);

  if (canSend) {
    eligibleItems.push({ json: item });
  } else {
    skippedItems.push({ title: tieuDe, reason: `Đã gửi ${soLanGui} lần hôm nay` });
  }
});

console.log(`[WF1 v8.1] Eligible: ${eligibleItems.length} | Skipped: ${skippedItems.length}`);

if (skippedItems.length > 0) {
  console.log('[WF1 v8.1] Skipped items:', JSON.stringify(skippedItems, null, 2));
}

return eligibleItems;

// ========================================
// WF1 v8.1 - PROCESS CLARIFICATION
// Entry IDs THỰC từ Form mới tạo 28/12/2025
// CC: hoangkha@esuhai.com trên MỌI email
// ========================================

const item = $input.first().json;
const properties = item.properties || {};

function getField(type, keywords) {
  for (const [name, data] of Object.entries(properties)) {
    if (data.type !== type) continue;
    const nameLower = name.toLowerCase();
    if (keywords.some(kw => nameLower.includes(kw.toLowerCase()))) {
      if (type === 'title') return data.title?.[0]?.plain_text || '';
      if (type === 'rich_text') return data.rich_text?.[0]?.plain_text || '';
      if (type === 'select') return data.select?.name || '';
      if (type === 'date') return data.date?.start || '';
      if (type === 'email') return data.email || '';
      if (type === 'number') return data.number || 0;
    }
  }
  return '';
}

// Extract fields
let tieuDe = '';
for (const [name, data] of Object.entries(properties)) {
  if (data.type === 'title' && data.title?.[0]) {
    tieuDe = data.title[0].plain_text || '';
    break;
  }
}

const tinhTrang = getField('select', ['tình trạng', 'status']);
const t2NhiemVu = getField('rich_text', ['nhiệm vụ', 't2']);
const t3ChiTieu = getField('rich_text', ['chỉ tiêu', 't3']);
const t4ThoiHan = getField('date', ['thời hạn', 't4', 'deadline']);
const nguonGiaoViec = getField('select', ['nguồn']);
const emailDauMoi = getField('email', ['email', 'đầu mối']);
const soLanGui = getField('number', ['số lần']) || 0;
const noiDungGoc = getField('rich_text', ['nội dung', 'gốc', 'original']);
const ngayNhan = getField('date', ['ngày nhận', 'received']);

// Get HR relation
let hrRelationId = '';
let t1Name = '';
for (const [name, data] of Object.entries(properties)) {
  if (data.type === 'relation') {
    const nameLower = name.toLowerCase();
    if (nameLower.includes('người nhận') || nameLower.includes('hr') || nameLower.includes('chỉ đạo') || nameLower.includes('đầu mối')) {
      if (data.relation && data.relation.length > 0) {
        hrRelationId = data.relation[0].id || '';
      }
      break;
    }
  }
}

// Determine email recipient
let emailSource = 'fallback';
let sendTo = 'vynnl@esuhai.com';
let needHRLookup = false;

if (emailDauMoi && emailDauMoi.includes('@')) {
  emailSource = 'direct_field';
  sendTo = emailDauMoi;
} else if (hrRelationId) {
  emailSource = 'hr_lookup';
  needHRLookup = true;
}

// ========================================
// BUILD PREFILL URL - Entry IDs THỰC
// Form: Làm rõ Chỉ đạo & Xác nhận Nhận việc
// Created: 28/12/2025
// ========================================
const formId = '1FAIpQLScD0T1ptDRydqDeVw7Q7rktnAvT7jHZlbIhqR175SRb9F2BrA';
const baseUrl = `https://docs.google.com/forms/d/e/${formId}/viewform?usp=pp_url`;

// Entry IDs THỰC từ form
const entryIds = {
  maClarification: '2121763497',
  nguonChiDao: '165701548',
  ngayNhanChiDao: '154144658',
  noiDungGoc: '1824948198',
  dauMoiT1: '1619940933',
  t2NhiemVu: '965316617',
  t3ChiTieu: '780968388',
  t4ThoiHan: '1750689024',
  ghiChu: '2087482442',
  xacNhan: '1109012960'
};

// Build params
const params = [
  `entry.${entryIds.maClarification}=${encodeURIComponent(item.id || '')}`,
  `entry.${entryIds.nguonChiDao}=${encodeURIComponent(nguonGiaoViec || 'CEO')}`,
  `entry.${entryIds.ngayNhanChiDao}=${encodeURIComponent(ngayNhan || new Date().toISOString().split('T')[0])}`,
  `entry.${entryIds.noiDungGoc}=${encodeURIComponent(noiDungGoc || tieuDe || '')}`,
  `entry.${entryIds.dauMoiT1}=${encodeURIComponent(t1Name || '')}`,
  `entry.${entryIds.t2NhiemVu}=${encodeURIComponent(t2NhiemVu || '')}`,
  `entry.${entryIds.t3ChiTieu}=${encodeURIComponent(t3ChiTieu || '')}`,
  `entry.${entryIds.t4ThoiHan}=${encodeURIComponent(t4ThoiHan || '')}`
].join('&');

const prefillUrl = `${baseUrl}&${params}`;

// Calculate new send count
const newSoLanGui = soLanGui + 1;
const today = new Date().toISOString().split('T')[0];

console.log(`[WF1 v8.1] Processing: "${tieuDe.substring(0, 40)}" | To: ${sendTo} | Count: ${soLanGui} → ${newSoLanGui}`);

return {
  clarificationId: item.id,
  clarificationUrl: item.url || `https://www.notion.so/${item.id.replace(/-/g, '')}`,
  tieuDe,
  tinhTrang,
  t2NhiemVu,
  t3ChiTieu,
  t4ThoiHan,
  nguonGiaoViec: nguonGiaoViec || 'CEO',
  noiDungGoc: noiDungGoc || tieuDe,
  ngayNhan: ngayNhan || today,
  emailSource,
  sendTo,
  // CC anh Kha trên MỌI email để theo dõi
  ccEmail: 'hoangkha@esuhai.com',
  bccEmail: '',
  hrRelationId,
  needHRLookup,
  prefillUrl,
  has4T: Boolean(tieuDe && t2NhiemVu && t3ChiTieu && t4ThoiHan),
  // Tracking
  oldSoLanGui: soLanGui,
  newSoLanGui: newSoLanGui,
  todayDate: today
};

// ========================================
// WF1 v8.1 - RESOLVE HR EMAIL
// Fallback nếu không tìm thấy email
// ========================================

const hrPage = $input.first().json;
const originalData = $('Process Clarification').item.json;

let hrEmail = '';
let hrName = '';
const props = hrPage.properties || {};

// Find email
for (const [name, data] of Object.entries(props)) {
  if (data.type === 'email' && data.email) {
    hrEmail = data.email;
    break;
  }
  if (data.type === 'rich_text' && data.rich_text?.[0]?.plain_text) {
    const text = data.rich_text[0].plain_text;
    if (text.includes('@')) {
      hrEmail = text.trim();
      break;
    }
  }
}

// Find name
for (const [name, data] of Object.entries(props)) {
  if (data.type === 'title' && data.title?.[0]) {
    hrName = data.title[0].plain_text || '';
    break;
  }
}

let sendTo = hrEmail || 'vynnl@esuhai.com';
let emailResolution = hrEmail ? 'hr_lookup' : 'fallback_from_hr';

console.log(`[WF1 v8.1] HR: ${hrName} | Email: ${hrEmail || '(none)'} → sendTo: ${sendTo}`);

// Rebuild prefill URL with HR name
const formId = '1FAIpQLScD0T1ptDRydqDeVw7Q7rktnAvT7jHZlbIhqR175SRb9F2BrA';
const baseUrl = `https://docs.google.com/forms/d/e/${formId}/viewform?usp=pp_url`;

const entryIds = {
  maClarification: '2121763497',
  nguonChiDao: '165701548',
  ngayNhanChiDao: '154144658',
  noiDungGoc: '1824948198',
  dauMoiT1: '1619940933',
  t2NhiemVu: '965316617',
  t3ChiTieu: '780968388',
  t4ThoiHan: '1750689024'
};

const params = [
  `entry.${entryIds.maClarification}=${encodeURIComponent(originalData.clarificationId || '')}`,
  `entry.${entryIds.nguonChiDao}=${encodeURIComponent(originalData.nguonGiaoViec || 'CEO')}`,
  `entry.${entryIds.ngayNhanChiDao}=${encodeURIComponent(originalData.ngayNhan || '')}`,
  `entry.${entryIds.noiDungGoc}=${encodeURIComponent(originalData.noiDungGoc || originalData.tieuDe || '')}`,
  `entry.${entryIds.dauMoiT1}=${encodeURIComponent(hrName || '')}`,
  `entry.${entryIds.t2NhiemVu}=${encodeURIComponent(originalData.t2NhiemVu || '')}`,
  `entry.${entryIds.t3ChiTieu}=${encodeURIComponent(originalData.t3ChiTieu || '')}`,
  `entry.${entryIds.t4ThoiHan}=${encodeURIComponent(originalData.t4ThoiHan || '')}`
].join('&');

const prefillUrl = `${baseUrl}&${params}`;

return {
  ...originalData,
  sendTo: sendTo,
  hrName: hrName,
  emailResolution: emailResolution,
  prefillUrl: prefillUrl
};

